window.GLOSSARY = {"afci":{"t":"AFCI (Arc-Fault Circuit Interrupter)","d":"A protective function that detects the electrical signature of a dangerous arc (a series or parallel fault) and de-energizes the circuit. NEC 690.11 requires DC arc-fault protection for most PV circuits to reduce fire risk.","u":"engineering-glossary.html#a"},"arc-fault circuit interrupter":{"t":"AFCI (Arc-Fault Circuit Interrupter)","d":"A protective function that detects the electrical signature of a dangerous arc (a series or parallel fault) and de-energizes the circuit. NEC 690.11 requires DC arc-fault protection for most PV circuits to reduce fire risk.","u":"engineering-glossary.html#a"},"agc":{"t":"AGC (Automatic Generation Control)","d":"A control scheme by which a balancing authority or plant controller automatically adjusts plant output in real time to follow dispatch signals and help maintain grid frequency; large solar and storage plants increasingly provide AGC-based regulation.","u":"engineering-glossary.html#a"},"automatic generation control":{"t":"AGC (Automatic Generation Control)","d":"A control scheme by which a balancing authority or plant controller automatically adjusts plant output in real time to follow dispatch signals and help maintain grid frequency; large solar and storage plants increasingly provide AGC-based regulation.","u":"engineering-glossary.html#a"},"ahj":{"t":"AHJ (Authority Having Jurisdiction)","d":"The office or official (typically a local building/electrical department or fire marshal) that adopts codes, reviews plans, issues permits, and inspects/approves the installation.","u":"engineering-glossary.html#a"},"authority having jurisdiction":{"t":"AHJ (Authority Having Jurisdiction)","d":"The office or official (typically a local building/electrical department or fire marshal) that adopts codes, reviews plans, issues permits, and inspects/approves the installation.","u":"engineering-glossary.html#a"},"air mass":{"t":"Air mass (AM)","d":"The relative path length of sunlight through the atmosphere versus straight overhead. STC uses AM 1.5, representing the sun ~48.2° from zenith; longer paths scatter and absorb more light.","u":"engineering-glossary.html#a"},"albedo":{"t":"Albedo","d":"The fraction of incident solar radiation reflected by the ground or surroundings (0–1). High albedo (snow, light gravel, white roofs) boosts bifacial module rear-side gain.","u":"engineering-glossary.html#a"},"ampacity":{"t":"Ampacity","d":"The maximum continuous current a conductor can carry without exceeding its temperature rating, after applying temperature-correction and conduit-fill adjustment factors (NEC Table 310.16 and 310.15).","u":"engineering-glossary.html#a"},"ancillary services":{"t":"Ancillary services","d":"Grid-support products procured by ISOs/RTOs and utilities beyond bulk energy — frequency regulation, spinning/non-spinning reserves, voltage support, and black start. Solar-plus-storage plants can supply several of these.","u":"engineering-glossary.html#a"},"array":{"t":"Array","d":"A mechanically and electrically integrated assembly of PV modules, strings, mounting, and supports forming a DC power-producing unit.","u":"engineering-glossary.html#a"},"augmentation":{"t":"Augmentation (storage)","d":"The planned addition of battery modules or racks over a project&#x27;s life to offset capacity lost to cell degradation, keeping a BESS at its contracted energy or power rating.","u":"engineering-glossary.html#a"},"storage":{"t":"Augmentation (storage)","d":"The planned addition of battery modules or racks over a project&#x27;s life to offset capacity lost to cell degradation, keeping a BESS at its contracted energy or power rating.","u":"engineering-glossary.html#a"},"availability":{"t":"Availability","d":"The fraction of time a system is able to operate and produce when resource is present, after subtracting outages for faults and maintenance. Performance contracts often guarantee availability (e.g. ≥98%).","u":"engineering-glossary.html#a"},"avoided cost":{"t":"Avoided cost","d":"The cost a utility avoids by not generating or purchasing power elsewhere; used as a basis for crediting exported energy under net-billing tariffs and for PURPA-qualifying facilities, typically well below retail rates.","u":"engineering-glossary.html#a"},"azimuth":{"t":"Azimuth","d":"The compass orientation of the array&#x27;s face, measured in degrees (0° = north, 90° = east, 180° = south, 270° = west). True south (180°) is generally optimal in the Northern Hemisphere.","u":"engineering-glossary.html#a"},"backtracking":{"t":"Backtracking","d":"A tracker control strategy that, near sunrise and sunset, rotates rows away from the ideal sun-facing angle to prevent rows from shading their neighbors, trading a little direct gain for a net energy improvement at high ground-coverage ratios.","u":"engineering-glossary.html#b"},"backup gateway":{"t":"Backup gateway","d":"A controller (sometimes called an automatic transfer/microgrid interconnection device) that detects a grid outage, isolates the home from the grid, and coordinates inverter/battery output to power backed-up loads while keeping the system from back-feeding the ","u":"engineering-glossary.html#b"},"balance of system":{"t":"Balance of System (BOS)","d":"All system components other than the modules: inverters, racking, wiring, combiners, disconnects, conduit, OCPD, monitoring, and labor.","u":"engineering-glossary.html#b"},"bos":{"t":"Balance of System (BOS)","d":"All system components other than the modules: inverters, racking, wiring, combiners, disconnects, conduit, OCPD, monitoring, and labor.","u":"engineering-glossary.html#b"},"ballasted system":{"t":"Ballasted system","d":"A flat-roof or ground mount held in place by weight (concrete blocks or trays) rather than roof penetrations, relying on dead load and friction; common on commercial membrane roofs to avoid waterproofing penetrations.","u":"engineering-glossary.html#b"},"behind-the-meter":{"t":"Behind-the-meter (BTM)","d":"Generation or storage located on the customer&#x27;s side of the utility revenue meter, primarily serving on-site load and reducing imports; contrast with front-of-the-meter.","u":"engineering-glossary.html#b"},"btm":{"t":"Behind-the-meter (BTM)","d":"Generation or storage located on the customer&#x27;s side of the utility revenue meter, primarily serving on-site load and reducing imports; contrast with front-of-the-meter.","u":"engineering-glossary.html#b"},"bess":{"t":"BESS (Battery Energy Storage System)","d":"A complete stationary storage installation comprising battery cells/modules, a battery management system, power conversion (inverters), thermal management, and controls, used for backup, energy shifting, and grid services.","u":"engineering-glossary.html#b"},"battery energy storage system":{"t":"BESS (Battery Energy Storage System)","d":"A complete stationary storage installation comprising battery cells/modules, a battery management system, power conversion (inverters), thermal management, and controls, used for backup, energy shifting, and grid services.","u":"engineering-glossary.html#b"},"bifacial":{"t":"Bifacial","d":"A module that generates power from both front and rear faces, capturing reflected (albedo) and diffuse light on the back side for extra yield.","u":"engineering-glossary.html#b"},"bipv":{"t":"BIPV (Building-Integrated Photovoltaics)","d":"PV that serves as part of the building envelope itself — solar shingles/tiles, façade cladding, or glazing — rather than being mounted on top of conventional roofing.","u":"engineering-glossary.html#b"},"building-integrated photovoltaics":{"t":"BIPV (Building-Integrated Photovoltaics)","d":"PV that serves as part of the building envelope itself — solar shingles/tiles, façade cladding, or glazing — rather than being mounted on top of conventional roofing.","u":"engineering-glossary.html#b"},"bonding":{"t":"Bonding","d":"See Grounding vs Bonding.","u":"engineering-glossary.html#b"},"bypass diode":{"t":"Bypass diode","d":"A diode built into a module&#x27;s junction box that routes current around a shaded or failed cell substring, preventing hot spots and limiting the production loss from partial shading.","u":"engineering-glossary.html#b"},"c&i":{"t":"C&I (Commercial & Industrial)","d":"The market segment of non-residential, non-utility customers (businesses, warehouses, factories, agriculture), typically served by larger BTM systems sized to demand and often shaped by demand charges.","u":"engineering-glossary.html#c"},"commercial & industrial":{"t":"C&I (Commercial & Industrial)","d":"The market segment of non-residential, non-utility customers (businesses, warehouses, factories, agriculture), typically served by larger BTM systems sized to demand and often shaped by demand charges.","u":"engineering-glossary.html#c"},"capacity factor":{"t":"Capacity factor","d":"The ratio of actual energy produced over a period to the energy that would be produced running at full rated (AC) power continuously: CF = Annual kWh ÷ (kW_AC × 8760). Fixed-tilt PV is typically 15–25%.","u":"engineering-glossary.html#c"},"capacity market":{"t":"Capacity market","d":"A forward market (run by several ISOs/RTOs such as PJM and ISO-NE) that pays resources to be available to meet future peak demand, providing a revenue stream distinct from energy sales.","u":"engineering-glossary.html#c"},"carport":{"t":"Carport / canopy","d":"An elevated PV structure built over a parking lot or walkway that provides shade and shelter while generating power; structurally more expensive per watt but uses otherwise idle land and can host EV charging.","u":"engineering-glossary.html#c"},"canopy":{"t":"Carport / canopy","d":"An elevated PV structure built over a parking lot or walkway that provides shade and shelter while generating power; structurally more expensive per watt but uses otherwise idle land and can host EV charging.","u":"engineering-glossary.html#c"},"c-rate":{"t":"C-rate","d":"A battery&#x27;s charge/discharge rate normalized to its capacity. A 1C rate fully charges or discharges in one hour; 0.5C in two hours. Lower C-rates (e.g. 0.25C, a 4-hour system) are common for grid storage.","u":"engineering-glossary.html#c"},"clipping":{"t":"Clipping","d":"The loss that occurs when array DC power exceeds the inverter&#x27;s AC rating and the inverter caps (clips) output at its maximum. Driven by a high DC/AC ratio (ILR); modest clipping is often economically optimal.","u":"engineering-glossary.html#c"},"collection system":{"t":"Collection system","d":"The medium-voltage cabling, trenches, and pad-mounted transformers that gather output from many inverters across a utility-scale plant and route it to the project substation.","u":"engineering-glossary.html#c"},"combiner box":{"t":"Combiner box","d":"An enclosure that parallels multiple PV strings onto larger output conductors, often housing string fuses (OCPD) and sometimes monitoring or DC disconnects.","u":"engineering-glossary.html#c"},"community solar":{"t":"Community solar","d":"A shared off-site array whose output is allocated to multiple subscribers via bill credits, letting renters and customers without suitable roofs participate; rules and compensation vary widely by state program.","u":"engineering-glossary.html#c"},"conductor":{"t":"Conductor (EGC / GEC)","d":"A wire carrying current or providing a fault/ground path. The Equipment Grounding Conductor (EGC) bonds equipment metal for fault clearing; the Grounding Electrode Conductor (GEC) connects the system to earth electrodes.","u":"engineering-glossary.html#c"},"egc":{"t":"Conductor (EGC / GEC)","d":"A wire carrying current or providing a fault/ground path. The Equipment Grounding Conductor (EGC) bonds equipment metal for fault clearing; the Grounding Electrode Conductor (GEC) connects the system to earth electrodes.","u":"engineering-glossary.html#c"},"gec":{"t":"Conductor (EGC / GEC)","d":"A wire carrying current or providing a fault/ground path. The Equipment Grounding Conductor (EGC) bonds equipment metal for fault clearing; the Grounding Electrode Conductor (GEC) connects the system to earth electrodes.","u":"engineering-glossary.html#c"},"critical loads panel":{"t":"Critical loads panel","d":"A subpanel (also &quot;backup loads panel&quot;) containing only the circuits intended to run during an outage, allowing a battery/backup system to power essential loads without having to support the entire home.","u":"engineering-glossary.html#c"},"curtailment":{"t":"Curtailment","d":"The deliberate reduction of available generation below what the resource could produce, due to grid congestion, oversupply, negative prices, or operator instruction; a growing factor in high-penetration solar regions.","u":"engineering-glossary.html#c"},"dc-to-ac ratio":{"t":"DC-to-AC ratio (ILR)","d":"Also Inverter Load Ratio: array DC nameplate divided by inverter AC nameplate, ILR = DC kWp ÷ AC kW. Typical economic range 1.15–1.35; values &gt;1.0 increase capacity factor at the cost of some clipping.","u":"engineering-glossary.html#d"},"ilr":{"t":"DC-to-AC ratio (ILR)","d":"Also Inverter Load Ratio: array DC nameplate divided by inverter AC nameplate, ILR = DC kWp ÷ AC kW. Typical economic range 1.15–1.35; values &gt;1.0 increase capacity factor at the cost of some clipping.","u":"engineering-glossary.html#d"},"degradation":{"t":"Degradation","d":"The gradual decline in module output over time, typically ~0.3–0.7%/year, plus an initial light-induced drop. Warranties commonly guarantee ~80–87% of nameplate at year 25.","u":"engineering-glossary.html#d"},"demand charge":{"t":"Demand charge","d":"A billing component based on a customer&#x27;s highest power draw (kW) during a period (often a 15-minute peak), independent of total energy used. Demand charges drive commercial storage and peak-shaving economics.","u":"engineering-glossary.html#d"},"demand ratchet":{"t":"Demand ratchet","d":"A tariff provision that sets a customer&#x27;s billed demand to a percentage of the highest peak recorded over preceding months, so a single high-demand interval can elevate charges long after it occurs.","u":"engineering-glossary.html#d"},"demand response":{"t":"Demand response (DR)","d":"Programs that pay or incentivize customers to reduce or shift load during grid stress events; on-site solar and storage can be dispatched to provide DR capacity.","u":"engineering-glossary.html#d"},"depth of discharge":{"t":"Depth of Discharge (DoD)","d":"The percentage of a battery&#x27;s capacity that has been discharged. Higher usable DoD increases available energy but can shorten cycle life depending on chemistry.","u":"engineering-glossary.html#d"},"dod":{"t":"Depth of Discharge (DoD)","d":"The percentage of a battery&#x27;s capacity that has been discharged. Higher usable DoD increases available energy but can shorten cycle life depending on chemistry.","u":"engineering-glossary.html#d"},"derate":{"t":"Derate","d":"A multiplicative reduction factor applied to ideal output to account for a real-world loss (temperature, soiling, wiring, inverter, mismatch, availability). The product of all derates yields the performance ratio.","u":"engineering-glossary.html#d"},"evse":{"t":"EVSE (Electric Vehicle Supply Equipment)","d":"The charging station hardware (the &quot;charger&quot;) that safely delivers AC or DC electricity to an electric vehicle; increasingly paired with solar and managed to charge during high production or off-peak periods.","u":"engineering-glossary.html#e"},"electric vehicle supply equipment":{"t":"EVSE (Electric Vehicle Supply Equipment)","d":"The charging station hardware (the &quot;charger&quot;) that safely delivers AC or DC electricity to an electric vehicle; increasingly paired with solar and managed to charge during high production or off-peak periods.","u":"engineering-glossary.html#e"},"ferc":{"t":"FERC (Federal Energy Regulatory Commission)","d":"The U.S. agency regulating interstate electricity transmission, wholesale power markets, and interconnection of large generators; FERC orders shape interconnection procedures and market rules.","u":"engineering-glossary.html#f"},"federal energy regulatory commission":{"t":"FERC (Federal Energy Regulatory Commission)","d":"The U.S. agency regulating interstate electricity transmission, wholesale power markets, and interconnection of large generators; FERC orders shape interconnection procedures and market rules.","u":"engineering-glossary.html#f"},"fill factor":{"t":"Fill factor (FF)","d":"A measure of an I-V curve&#x27;s &quot;squareness&quot; and cell quality: FF = (Vmp × Imp) ÷ (Voc × Isc). Higher FF (typically 0.7–0.85) indicates a better-performing cell.","u":"engineering-glossary.html#f"},"front-of-the-meter":{"t":"Front-of-the-meter (FTM)","d":"Generation or storage connected to the grid on the utility side of the customer meter, selling energy or services into wholesale markets; contrast with behind-the-meter.","u":"engineering-glossary.html#f"},"ftm":{"t":"Front-of-the-meter (FTM)","d":"Generation or storage connected to the grid on the utility side of the customer meter, selling energy or services into wholesale markets; contrast with behind-the-meter.","u":"engineering-glossary.html#f"},"gen-tie line":{"t":"Gen-tie line","d":"The &quot;generation tie&quot; — the high- or medium-voltage line that carries a utility-scale plant&#x27;s output from its substation/switchyard to the point of interconnection with the grid.","u":"engineering-glossary.html#g"},"geotechnical":{"t":"Geotechnical","d":"The subsurface soil investigation (borings, resistivity, corrosion, bearing capacity) that informs pile design, grounding, and foundations for ground-mount and utility-scale projects.","u":"engineering-glossary.html#g"},"gfci":{"t":"GFCI / GFDI (Ground-Fault Protection)","d":"Functions that detect current leaking to ground and interrupt the circuit. Residential AC outlets use GFCI; PV arrays use ground-fault detection/interruption per NEC 690.5 to limit shock and fire hazards.","u":"engineering-glossary.html#g"},"gfdi":{"t":"GFCI / GFDI (Ground-Fault Protection)","d":"Functions that detect current leaking to ground and interrupt the circuit. Residential AC outlets use GFCI; PV arrays use ground-fault detection/interruption per NEC 690.5 to limit shock and fire hazards.","u":"engineering-glossary.html#g"},"ground-fault protection":{"t":"GFCI / GFDI (Ground-Fault Protection)","d":"Functions that detect current leaking to ground and interrupt the circuit. Residential AC outlets use GFCI; PV arrays use ground-fault detection/interruption per NEC 690.5 to limit shock and fire hazards.","u":"engineering-glossary.html#g"},"grid-forming vs grid-following":{"t":"Grid-forming vs grid-following","d":"A grid-following inverter synchronizes to an existing grid voltage/frequency reference and injects current accordingly. A grid-forming inverter actively establishes its own voltage and frequency, enabling islanding, black start, and stability on low-inertia gr","u":"engineering-glossary.html#g"},"ground-coverage ratio":{"t":"Ground-coverage ratio (GCR)","d":"The ratio of module (collector) area to total ground/land area, GCR = row width ÷ row pitch. Higher GCR packs more capacity per acre but increases inter-row shading and backtracking losses.","u":"engineering-glossary.html#g"},"gcr":{"t":"Ground-coverage ratio (GCR)","d":"The ratio of module (collector) area to total ground/land area, GCR = row width ÷ row pitch. Higher GCR packs more capacity per acre but increases inter-row shading and backtracking losses.","u":"engineering-glossary.html#g"},"grounding vs bonding":{"t":"Grounding vs Bonding","d":"Bonding electrically connects metal parts together to a common potential for fault-current return; Grounding connects the bonded system to earth. Both are required for safety; they are distinct functions often conflated.","u":"engineering-glossary.html#g"},"hosting capacity":{"t":"Hosting capacity","d":"The amount of additional distributed generation a given point on the distribution grid can accept without requiring upgrades or violating voltage/thermal limits; utilities publish hosting-capacity maps to guide siting.","u":"engineering-glossary.html#h"},"hsat":{"t":"HSAT (Horizontal Single-Axis Tracker)","d":"The dominant utility-scale tracker geometry, rotating rows about a horizontal north-south axis to follow the sun east-to-west; pairs with backtracking to limit row-to-row shading.","u":"engineering-glossary.html#h"},"horizontal single-axis tracker":{"t":"HSAT (Horizontal Single-Axis Tracker)","d":"The dominant utility-scale tracker geometry, rotating rows about a horizontal north-south axis to follow the sun east-to-west; pairs with backtracking to limit row-to-row shading.","u":"engineering-glossary.html#h"},"hybrid inverter":{"t":"Hybrid inverter","d":"An inverter that manages PV, battery storage, and grid/loads in one unit, supporting charging, discharging, backup, and (often) islanding during outages.","u":"engineering-glossary.html#h"},"insolation":{"t":"Insolation","d":"Solar energy received per unit area over time (Wh/m² or kWh/m²), as distinct from instantaneous irradiance. Daily insolation in kWh/m² equals the day&#x27;s peak sun hours.","u":"engineering-glossary.html#i"},"interconnection":{"t":"Interconnection","d":"The electrical and contractual connection of a PV system to the utility grid, governed by NEC Article 705 and the utility&#x27;s interconnection agreement/standards.","u":"engineering-glossary.html#i"},"interconnection queue":{"t":"Interconnection queue","d":"The ordered list of proposed generation/storage projects awaiting study and approval to connect to the transmission system; long queues and cluster studies are a major utility-scale development bottleneck.","u":"engineering-glossary.html#i"},"inverter":{"t":"Inverter","d":"The device that converts module DC power to grid-synchronized AC power, performing maximum power point tracking, anti-islanding, and grid-support functions. Types: string, central, micro, and hybrid.","u":"engineering-glossary.html#i"},"irradiance":{"t":"Irradiance","d":"Instantaneous solar power density, in W/m². The STC reference is 1000 W/m².","u":"engineering-glossary.html#i"},"iso":{"t":"ISO / RTO","d":"An Independent System Operator or Regional Transmission Organization that operates the bulk grid, runs wholesale energy/ancillary markets, and administers interconnection across a region (e.g. CAISO, PJM, ERCOT, MISO, ISO-NE, NYISO, SPP).","u":"engineering-glossary.html#i"},"rto":{"t":"ISO / RTO","d":"An Independent System Operator or Regional Transmission Organization that operates the bulk grid, runs wholesale energy/ancillary markets, and administers interconnection across a region (e.g. CAISO, PJM, ERCOT, MISO, ISO-NE, NYISO, SPP).","u":"engineering-glossary.html#i"},"i-v curve":{"t":"I-V curve","d":"The current-versus-voltage characteristic of a cell, module, or string. Key points: short-circuit (Isc), open-circuit (Voc), and the maximum power point (Pmax at Vmp, Imp).","u":"engineering-glossary.html#i"},"kw vs kwh":{"t":"kW vs kWh","d":"Kilowatt (kW) is power (instantaneous rate, e.g. system size); kilowatt-hour (kWh) is energy (power × time, e.g. monthly bill). A 5 kW system running 4 peak sun hours produces ~20 kWh.","u":"engineering-glossary.html#k"},"lcoe":{"t":"LCOE (Levelized Cost of Energy)","d":"The discounted lifetime cost of a system divided by its discounted lifetime energy output, expressed in $/kWh; the per-unit cost at which the project breaks even.","u":"engineering-glossary.html#l"},"levelized cost of energy":{"t":"LCOE (Levelized Cost of Energy)","d":"The discounted lifetime cost of a system divided by its discounted lifetime energy output, expressed in $/kWh; the per-unit cost at which the project breaks even.","u":"engineering-glossary.html#l"},"lgia":{"t":"LGIA / SGIA","d":"The Large and Small Generator Interconnection Agreement — the FERC-jurisdictional contracts governing how a generator connects to the transmission grid, defining facilities, cost responsibility, and operating obligations (typically split at 20 MW).","u":"engineering-glossary.html#l"},"sgia":{"t":"LGIA / SGIA","d":"The Large and Small Generator Interconnection Agreement — the FERC-jurisdictional contracts governing how a generator connects to the transmission grid, defining facilities, cost responsibility, and operating obligations (typically split at 20 MW).","u":"engineering-glossary.html#l"},"line-side tap":{"t":"Line-side tap","d":"A supply-side connection that taps PV/storage onto the service conductors between the utility and the main service disconnect (NEC 705.11), avoiding the 120% busbar rule and often used when load-side capacity is insufficient.","u":"engineering-glossary.html#l"},"lmp":{"t":"LMP / nodal pricing","d":"Locational Marginal Pricing: the wholesale energy price at a specific grid node, reflecting marginal generation cost plus congestion and losses. Solar revenue in merchant markets depends on the LMP at the plant&#x27;s node.","u":"engineering-glossary.html#l"},"nodal pricing":{"t":"LMP / nodal pricing","d":"Locational Marginal Pricing: the wholesale energy price at a specific grid node, reflecting marginal generation cost plus congestion and losses. Solar revenue in merchant markets depends on the LMP at the plant&#x27;s node.","u":"engineering-glossary.html#l"},"load factor":{"t":"Load factor","d":"The ratio of average load to peak load over a period; a low load factor (spiky demand) signals high demand-charge exposure and good candidacy for peak shaving.","u":"engineering-glossary.html#l"},"load shifting":{"t":"Load shifting","d":"Using storage or controllable loads to move energy consumption from high-price/high-demand periods to lower-cost periods, without necessarily reducing total energy used.","u":"engineering-glossary.html#l"},"load-side connection":{"t":"Load-side connection","d":"A PV/storage interconnection on the customer side of the main breaker — typically a back-fed breaker in the main panel or a subpanel — subject to the NEC 705.12 busbar/120% (or other listed) rule.","u":"engineering-glossary.html#l"},"lvrt":{"t":"LVRT / HVRT (Low-/High-Voltage Ride-Through)","d":"Inverter capability (required by IEEE 1547 and interconnection rules) to remain connected and supportive through brief grid voltage sags or swells rather than tripping offline, improving grid stability.","u":"engineering-glossary.html#l"},"hvrt":{"t":"LVRT / HVRT (Low-/High-Voltage Ride-Through)","d":"Inverter capability (required by IEEE 1547 and interconnection rules) to remain connected and supportive through brief grid voltage sags or swells rather than tripping offline, improving grid stability.","u":"engineering-glossary.html#l"},"low-":{"t":"LVRT / HVRT (Low-/High-Voltage Ride-Through)","d":"Inverter capability (required by IEEE 1547 and interconnection rules) to remain connected and supportive through brief grid voltage sags or swells rather than tripping offline, improving grid stability.","u":"engineering-glossary.html#l"},"high-voltage ride-through":{"t":"LVRT / HVRT (Low-/High-Voltage Ride-Through)","d":"Inverter capability (required by IEEE 1547 and interconnection rules) to remain connected and supportive through brief grid voltage sags or swells rather than tripping offline, improving grid stability.","u":"engineering-glossary.html#l"},"main panel upgrade":{"t":"Main panel upgrade (MPU)","d":"Replacing a home&#x27;s main service panel/busbar (e.g. from 100 A to 200 A) to provide capacity for solar back-feed, batteries, EV charging, or electrification when the existing panel cannot accommodate the addition under NEC 705.12.","u":"engineering-glossary.html#m"},"mpu":{"t":"Main panel upgrade (MPU)","d":"Replacing a home&#x27;s main service panel/busbar (e.g. from 100 A to 200 A) to provide capacity for solar back-feed, batteries, EV charging, or electrification when the existing panel cannot accommodate the addition under NEC 705.12.","u":"engineering-glossary.html#m"},"medium voltage":{"t":"Medium voltage (MV)","d":"Distribution-class voltages roughly 1 kV–35 kV (commonly 12.47–34.5 kV in solar collection systems) at which utility-scale plants gather and transmit power before final step-up.","u":"engineering-glossary.html#m"},"merchant plant":{"t":"Merchant plant","d":"A generation project that sells its output at fluctuating wholesale market prices rather than under a fixed long-term contract, taking on price (and often shape) risk in exchange for upside.","u":"engineering-glossary.html#m"},"microinverter":{"t":"Microinverter","d":"A small inverter mounted at each module (or pair), converting DC to AC at the module level for per-module MPPT, monitoring, and inherent module-level rapid shutdown.","u":"engineering-glossary.html#m"},"mlpe":{"t":"MLPE (Module-Level Power Electronics)","d":"Devices attached to individual modules — microinverters or DC optimizers — that provide per-module MPPT, monitoring, and rapid-shutdown capability, improving yield under mismatch/shade.","u":"engineering-glossary.html#m"},"module-level power electronics":{"t":"MLPE (Module-Level Power Electronics)","d":"Devices attached to individual modules — microinverters or DC optimizers — that provide per-module MPPT, monitoring, and rapid-shutdown capability, improving yield under mismatch/shade.","u":"engineering-glossary.html#m"},"module":{"t":"Module","d":"A single, factory-assembled, environmentally sealed panel of interconnected PV cells — the basic building block of an array. (A &quot;panel&quot; colloquially.)","u":"engineering-glossary.html#m"},"mppt":{"t":"MPPT (Maximum Power Point Tracking)","d":"The inverter/optimizer algorithm that continuously adjusts operating voltage to keep the array at its maximum-power point as irradiance and temperature change.","u":"engineering-glossary.html#m"},"maximum power point tracking":{"t":"MPPT (Maximum Power Point Tracking)","d":"The inverter/optimizer algorithm that continuously adjusts operating voltage to keep the array at its maximum-power point as irradiance and temperature change.","u":"engineering-glossary.html#m"},"nabcep":{"t":"NABCEP","d":"The North American Board of Certified Energy Practitioners, the leading voluntary certification body for solar installers, designers, and inspectors in North America.","u":"engineering-glossary.html#n"},"nem 3.0":{"t":"NEM 3.0 / Net billing","d":"California&#x27;s Net Billing Tariff (effective April 15, 2023), which credits exported solar at hourly avoided-cost (ACC) values — typically a small fraction of retail — rather than retail-rate net metering, sharply improving the economics of pairing solar with st","u":"engineering-glossary.html#n"},"net billing":{"t":"NEM 3.0 / Net billing","d":"California&#x27;s Net Billing Tariff (effective April 15, 2023), which credits exported solar at hourly avoided-cost (ACC) values — typically a small fraction of retail — rather than retail-rate net metering, sharply improving the economics of pairing solar with st","u":"engineering-glossary.html#n"},"nepa":{"t":"NEPA (National Environmental Policy Act)","d":"The federal law requiring environmental review (e.g. environmental assessment or impact statement) for projects with federal involvement, such as solar on federal land or with federal permits; a key utility-scale development milestone.","u":"engineering-glossary.html#n"},"national environmental policy act":{"t":"NEPA (National Environmental Policy Act)","d":"The federal law requiring environmental review (e.g. environmental assessment or impact statement) for projects with federal involvement, such as solar on federal land or with federal permits; a key utility-scale development milestone.","u":"engineering-glossary.html#n"},"nerc":{"t":"NERC / NERC CIP","d":"The North American Electric Reliability Corporation sets and enforces mandatory bulk-power reliability standards; its Critical Infrastructure Protection (CIP) standards impose cybersecurity and physical-security requirements on qualifying generation and contro","u":"engineering-glossary.html#n"},"nerc cip":{"t":"NERC / NERC CIP","d":"The North American Electric Reliability Corporation sets and enforces mandatory bulk-power reliability standards; its Critical Infrastructure Protection (CIP) standards impose cybersecurity and physical-security requirements on qualifying generation and contro","u":"engineering-glossary.html#n"},"net metering vs net billing":{"t":"Net metering vs Net billing","d":"Under net metering, exported energy offsets imported energy at (near) retail value, typically kWh-for-kWh. Under net billing, exports are credited at a separate, usually lower, rate (e.g. avoided cost) while imports are billed at retail.","u":"engineering-glossary.html#n"},"nfpa 855":{"t":"NFPA 855","d":"The NFPA Standard for the Installation of Stationary Energy Storage Systems, governing siting, separation, ventilation, and fire protection for BESS. The 2026 edition makes large-scale fire testing mandatory and references UL 9540A for that testing.","u":"engineering-glossary.html#n"},"noct":{"t":"NOCT (Nominal Operating Cell Temperature)","d":"The cell temperature under defined real-world conditions (800 W/m², 20 °C ambient, 1 m/s wind), typically ~43–48 °C — a more realistic basis than STC for field temperatures.","u":"engineering-glossary.html#n"},"nominal operating cell temperature":{"t":"NOCT (Nominal Operating Cell Temperature)","d":"The cell temperature under defined real-world conditions (800 W/m², 20 °C ambient, 1 m/s wind), typically ~43–48 °C — a more realistic basis than STC for field temperatures.","u":"engineering-glossary.html#n"},"ocpd":{"t":"OCPD (Overcurrent Protective Device)","d":"A fuse or circuit breaker that protects conductors and equipment from over-current; sized per NEC 690.9 (PV) and 240.6 (standard ratings).","u":"engineering-glossary.html#o"},"overcurrent protective device":{"t":"OCPD (Overcurrent Protective Device)","d":"A fuse or circuit breaker that protects conductors and equipment from over-current; sized per NEC 690.9 (PV) and 240.6 (standard ratings).","u":"engineering-glossary.html#o"},"optimizer":{"t":"Optimizer","d":"A module-level DC-DC power electronics device that performs per-module MPPT and reports data while a central string inverter handles DC-to-AC conversion; also provides module-level rapid shutdown.","u":"engineering-glossary.html#o"},"p50":{"t":"P50 / P90","d":"Probabilistic energy estimates from a production model. P50 is the median expected annual yield (50% chance of exceedance); P90 is the conservative value exceeded 90% of years, used by lenders to size debt.","u":"engineering-glossary.html#p"},"p90":{"t":"P50 / P90","d":"Probabilistic energy estimates from a production model. P50 is the median expected annual yield (50% chance of exceedance); P90 is the conservative value exceeded 90% of years, used by lenders to size debt.","u":"engineering-glossary.html#p"},"peak shaving":{"t":"Peak shaving","d":"Dispatching storage (or curtailing/shifting load) to clip a facility&#x27;s highest demand intervals, reducing demand charges and grid stress.","u":"engineering-glossary.html#p"},"perc":{"t":"PERC (Passivated Emitter and Rear Cell)","d":"A mainstream silicon cell architecture adding a rear passivation layer to reflect light back into the cell and reduce recombination, raising efficiency over standard cells.","u":"engineering-glossary.html#p"},"passivated emitter and rear cell":{"t":"PERC (Passivated Emitter and Rear Cell)","d":"A mainstream silicon cell architecture adding a rear passivation layer to reflect light back into the cell and reduce recombination, raising efficiency over standard cells.","u":"engineering-glossary.html#p"},"performance ratio":{"t":"Performance ratio (PR)","d":"The ratio of actual delivered AC energy to the theoretical energy at rated DC power and measured irradiance; the product of all loss factors. Modern systems typically reach PR ≈ 0.78–0.84.","u":"engineering-glossary.html#p"},"permission to operate":{"t":"Permission to Operate (PTO)","d":"The utility&#x27;s formal authorization, issued after interconnection approval and inspection sign-off, allowing a system to energize and export; the milestone that starts billing under the chosen tariff.","u":"engineering-glossary.html#p"},"pto":{"t":"Permission to Operate (PTO)","d":"The utility&#x27;s formal authorization, issued after interconnection approval and inspection sign-off, allowing a system to energize and export; the milestone that starts billing under the chosen tariff.","u":"engineering-glossary.html#p"},"photovoltaic effect":{"t":"Photovoltaic effect","d":"The physical phenomenon by which a semiconductor generates voltage and current when exposed to light, separating photo-excited electron-hole pairs across a p-n junction.","u":"engineering-glossary.html#p"},"pile refusal":{"t":"Pile refusal","d":"The condition where a driven foundation pile cannot advance to its design depth (hitting rock or hard soil), requiring pre-drilling, redesign, or alternative foundations — a schedule and cost risk on ground mounts.","u":"engineering-glossary.html#p"},"point of interconnection":{"t":"Point of interconnection (POI)","d":"The exact location where the PV system electrically connects to the utility/premises wiring (e.g. a back-fed breaker, line-side tap, or dedicated meter); central to NEC 705.12/705.11 compliance and, at utility scale, the metered grid boundary.","u":"engineering-glossary.html#p"},"poi":{"t":"Point of interconnection (POI)","d":"The exact location where the PV system electrically connects to the utility/premises wiring (e.g. a back-fed breaker, line-side tap, or dedicated meter); central to NEC 705.12/705.11 compliance and, at utility scale, the metered grid boundary.","u":"engineering-glossary.html#p"},"power factor":{"t":"Power factor (pf)","d":"The ratio of real power to apparent power, pf = P ÷ S = cos(θ) (0–1). Grid-tied inverters usually run near unity unless commanded to supply/absorb reactive power.","u":"engineering-glossary.html#p"},"power factor correction":{"t":"Power factor correction","d":"Adding capacitors or commanding inverters to supply reactive power so a facility&#x27;s power factor approaches unity, reducing apparent-power (kVA) demand and avoiding low-power-factor penalties.","u":"engineering-glossary.html#p"},"power plant controller":{"t":"Power plant controller (PPC)","d":"The plant-level supervisory controller at a utility-scale solar/storage facility that coordinates all inverters to meet POI setpoints for real power, reactive power/voltage, ramp rate, and grid-operator dispatch.","u":"engineering-glossary.html#p"},"ppc":{"t":"Power plant controller (PPC)","d":"The plant-level supervisory controller at a utility-scale solar/storage facility that coordinates all inverters to meet POI setpoints for real power, reactive power/voltage, ramp rate, and grid-operator dispatch.","u":"engineering-glossary.html#p"},"power purchase agreement":{"t":"Power purchase agreement (PPA)","d":"A contract under which a third party owns the system and sells the produced electricity to the host (or to a utility/offtaker) at an agreed $/kWh rate, often with no upfront cost to the host.","u":"engineering-glossary.html#p"},"ppa":{"t":"Power purchase agreement (PPA)","d":"A contract under which a third party owns the system and sells the produced electricity to the host (or to a utility/offtaker) at an agreed $/kWh rate, often with no upfront cost to the host.","u":"engineering-glossary.html#p"},"peak sun hours":{"t":"Peak sun hours (PSH)","d":"The equivalent number of hours per day of 1000 W/m² irradiance that yields the same daily insolation; numerically equal to daily plane-of-array insolation in kWh/m².","u":"engineering-glossary.html#p"},"psh":{"t":"Peak sun hours (PSH)","d":"The equivalent number of hours per day of 1000 W/m² irradiance that yields the same daily insolation; numerically equal to daily plane-of-array insolation in kWh/m².","u":"engineering-glossary.html#p"},"ptc":{"t":"PTC (PVUSA Test Conditions)","d":"A rating condition (1000 W/m², 20 °C ambient, 1 m/s wind) that gives a more field-representative power figure than STC; PTC ratings are typically a few percent below STC.","u":"engineering-glossary.html#p"},"pvusa test conditions":{"t":"PTC (PVUSA Test Conditions)","d":"A rating condition (1000 W/m², 20 °C ambient, 1 m/s wind) that gives a more field-representative power figure than STC; PTC ratings are typically a few percent below STC.","u":"engineering-glossary.html#p"},"photovoltaic":{"t":"PV (Photovoltaic)","d":"Pertaining to the direct conversion of light into electricity via the photovoltaic effect.","u":"engineering-glossary.html#p"},"rapid shutdown":{"t":"Rapid shutdown","d":"An NEC 690.12 requirement to quickly reduce conductor voltage within and near the array (to safe levels) for firefighter safety, satisfied by module-level electronics (micros/optimizers) or compliant equipment.","u":"engineering-glossary.html#r"},"reactive power":{"t":"Reactive power / VAR","d":"Power that oscillates between source and load without doing net work, measured in volt-amperes reactive (VAR); managing reactive power supports grid voltage. Smart inverters can absorb or supply VARs on command.","u":"engineering-glossary.html#r"},"var":{"t":"Reactive power / VAR","d":"Power that oscillates between source and load without doing net work, measured in volt-amperes reactive (VAR); managing reactive power supports grid voltage. Smart inverters can absorb or supply VARs on command.","u":"engineering-glossary.html#r"},"rec":{"t":"REC (Renewable Energy Certificate)","d":"A tradable certificate representing the environmental attributes of 1 MWh of renewable generation, sold separately from the underlying energy.","u":"engineering-glossary.html#r"},"renewable energy certificate":{"t":"REC (Renewable Energy Certificate)","d":"A tradable certificate representing the environmental attributes of 1 MWh of renewable generation, sold separately from the underlying energy.","u":"engineering-glossary.html#r"},"repowering":{"t":"Repowering","d":"Upgrading an existing plant — replacing aging modules, inverters, or trackers, or adding storage — to restore or increase output and extend operating life.","u":"engineering-glossary.html#r"},"ride-through":{"t":"Ride-through","d":"See LVRT / HVRT.","u":"engineering-glossary.html#r"},"rocof":{"t":"ROCOF (Rate of Change of Frequency)","d":"How fast grid frequency changes (Hz/s) after a disturbance. Low-inertia, inverter-dominated grids see steeper ROCOF, raising the importance of fast frequency response and grid-forming inverters.","u":"engineering-glossary.html#r"},"rate of change of frequency":{"t":"ROCOF (Rate of Change of Frequency)","d":"How fast grid frequency changes (Hz/s) after a disturbance. Low-inertia, inverter-dominated grids see steeper ROCOF, raising the importance of fast frequency response and grid-forming inverters.","u":"engineering-glossary.html#r"},"round-trip efficiency":{"t":"Round-trip efficiency (RTE)","d":"The ratio of energy a storage system delivers on discharge to the energy put in to charge it, accounting for conversion and losses; lithium-ion BESS typically achieve ~85–92%.","u":"engineering-glossary.html#r"},"rte":{"t":"Round-trip efficiency (RTE)","d":"The ratio of energy a storage system delivers on discharge to the energy put in to charge it, accounting for conversion and losses; lithium-ion BESS typically achieve ~85–92%.","u":"engineering-glossary.html#r"},"rps":{"t":"RPS (Renewable Portfolio Standard)","d":"A state mandate requiring load-serving entities to source a minimum share of electricity from renewables, often met by retiring RECs/SRECs; a primary driver of solar demand.","u":"engineering-glossary.html#r"},"renewable portfolio standard":{"t":"RPS (Renewable Portfolio Standard)","d":"A state mandate requiring load-serving entities to source a minimum share of electricity from renewables, often met by retiring RECs/SRECs; a primary driver of solar demand.","u":"engineering-glossary.html#r"},"scada":{"t":"SCADA (Supervisory Control and Data Acquisition)","d":"The monitoring and control system that gathers telemetry from plant equipment and relays operator/PPC commands; the operational backbone of utility-scale solar and storage.","u":"engineering-glossary.html#s"},"supervisory control and data acquisition":{"t":"SCADA (Supervisory Control and Data Acquisition)","d":"The monitoring and control system that gathers telemetry from plant equipment and relays operator/PPC commands; the operational backbone of utility-scale solar and storage.","u":"engineering-glossary.html#s"},"sgip":{"t":"SGIP","d":"See state program references in Sources; broadly, incentive programs (e.g. California&#x27;s Self-Generation Incentive Program) that subsidize behind-the-meter storage.","u":"engineering-glossary.html#s"},"smart":{"t":"SMART","d":"Massachusetts&#x27;s Solar Massachusetts Renewable Target program, a declining-block tariff incentive that supported residential through utility-scale solar; its capacity has been largely succeeded by the SuSI program.","u":"engineering-glossary.html#s"},"solar access":{"t":"Solar access","d":"The legal and physical right to unobstructed sunlight reaching an array; protected in some jurisdictions by solar-access laws, easements, or solar-rights statutes against shading by neighboring structures or vegetation.","u":"engineering-glossary.html#s"},"solarapp+":{"t":"SolarAPP+","d":"An NREL-developed Solar Automated Permit Processing platform that lets participating AHJs instantly review and approve code-compliant residential solar and solar-plus-storage permits online, cutting permitting time; adopted by 160+ communities.","u":"engineering-glossary.html#s"},"solar lease":{"t":"Solar lease","d":"A financing arrangement in which a host pays a fixed (often escalating) monthly amount to use a third-party-owned system, as opposed to buying the energy by the kWh under a PPA.","u":"engineering-glossary.html#s"},"solar noon":{"t":"Solar noon","d":"The moment the sun crosses the local meridian (due south/north) and reaches its highest daily elevation; the reference time for peak irradiance and shading calculations.","u":"engineering-glossary.html#s"},"solar shingle":{"t":"Solar shingle","d":"A BIPV roofing product that integrates PV cells into shingle/tile form, replacing conventional roofing while generating power; aesthetically driven and generally costlier per watt than rack-mounted modules.","u":"engineering-glossary.html#s"},"soc":{"t":"SOC (State of Charge)","d":"The present energy in a battery as a percentage of its usable capacity (0–100%); the core operating variable a battery management system regulates and dispatch schedules target.","u":"engineering-glossary.html#s"},"state of charge":{"t":"SOC (State of Charge)","d":"The present energy in a battery as a percentage of its usable capacity (0–100%); the core operating variable a battery management system regulates and dispatch schedules target.","u":"engineering-glossary.html#s"},"specific yield":{"t":"Specific yield","d":"Annual AC energy normalized to installed DC capacity, kWh ÷ kWp; enables comparison across system sizes and locations (typically ~1,100–1,900+ kWh/kWp/yr).","u":"engineering-glossary.html#s"},"srec":{"t":"SREC (Solar Renewable Energy Certificate)","d":"A REC specific to solar generation, used in state solar carve-out / RPS programs and often more valuable than generic RECs.","u":"engineering-glossary.html#s"},"solar renewable energy certificate":{"t":"SREC (Solar Renewable Energy Certificate)","d":"A REC specific to solar generation, used in state solar carve-out / RPS programs and often more valuable than generic RECs.","u":"engineering-glossary.html#s"},"stc":{"t":"STC (Standard Test Conditions)","d":"The lab reference for rating modules: 1000 W/m² irradiance, 25 °C cell temperature, AM 1.5 spectrum. Nameplate watt ratings are at STC.","u":"engineering-glossary.html#s"},"standard test conditions":{"t":"STC (Standard Test Conditions)","d":"The lab reference for rating modules: 1000 W/m² irradiance, 25 °C cell temperature, AM 1.5 spectrum. Nameplate watt ratings are at STC.","u":"engineering-glossary.html#s"},"string":{"t":"String","d":"A group of PV modules wired in series; the series count sets the string voltage, which must stay within the inverter&#x27;s MPPT and maximum-input window across temperature extremes.","u":"engineering-glossary.html#s"},"substation":{"t":"Substation","d":"The facility that steps a utility-scale plant&#x27;s medium-voltage collected output up to transmission voltage and houses protection, metering, and switching before the gen-tie carries power to the grid.","u":"engineering-glossary.html#s"},"susi":{"t":"SuSI (Solar for All / SMART successor)","d":"Massachusetts&#x27;s successor incentive framework to the SMART program, restructuring distributed-solar compensation across residential, low-income, commercial, and larger projects.","u":"engineering-glossary.html#s"},"solar for all":{"t":"SuSI (Solar for All / SMART successor)","d":"Massachusetts&#x27;s successor incentive framework to the SMART program, restructuring distributed-solar compensation across residential, low-income, commercial, and larger projects.","u":"engineering-glossary.html#s"},"smart successor":{"t":"SuSI (Solar for All / SMART successor)","d":"Massachusetts&#x27;s successor incentive framework to the SMART program, restructuring distributed-solar compensation across residential, low-income, commercial, and larger projects.","u":"engineering-glossary.html#s"},"switchyard":{"t":"SwitchYard","d":"The high-voltage switching and protection area (breakers, disconnects, buswork) at a substation or interconnection point where the plant ties to the transmission system.","u":"engineering-glossary.html#s"},"tax equity":{"t":"Tax equity","d":"A financing structure in which an investor with tax liability funds part of a project in exchange for federal tax credits (ITC/PTC) and depreciation benefits, monetizing incentives the developer cannot fully use itself.","u":"engineering-glossary.html#t"},"temperature coefficient":{"t":"Temperature coefficient","d":"The percentage change in a module parameter (Voc, Vmp, Isc, or Pmax) per °C deviation from 25 °C STC. Voltage coefficients are negative (voltage rises as temperature falls), critical for cold-Voc string sizing.","u":"engineering-glossary.html#t"},"tilt":{"t":"Tilt","d":"The angle of the array plane from horizontal (0° = flat, 90° = vertical). Annual-optimal tilt is roughly the site latitude; steeper favors winter, shallower favors summer.","u":"engineering-glossary.html#t"},"time-of-use":{"t":"Time-of-use (TOU)","d":"A rate structure in which the per-kWh price varies by time of day and season, with higher on-peak (often evening) prices; TOU shifts the value of solar and motivates storage to discharge during peak windows.","u":"engineering-glossary.html#t"},"tou":{"t":"Time-of-use (TOU)","d":"A rate structure in which the per-kWh price varies by time of day and season, with higher on-peak (often evening) prices; TOU shifts the value of solar and motivates storage to discharge during peak windows.","u":"engineering-glossary.html#t"},"tmy":{"t":"TMY (Typical Meteorological Year)","d":"A synthesized one-year dataset of hourly weather/irradiance representing long-term typical conditions at a site, used as the standard input for energy-yield simulations.","u":"engineering-glossary.html#t"},"typical meteorological year":{"t":"TMY (Typical Meteorological Year)","d":"A synthesized one-year dataset of hourly weather/irradiance representing long-term typical conditions at a site, used as the standard input for energy-yield simulations.","u":"engineering-glossary.html#t"},"topcon":{"t":"TOPCon / HJT","d":"Advanced high-efficiency silicon cell technologies. TOPCon (Tunnel Oxide Passivated Contact) adds an ultrathin oxide and doped poly-silicon layer; HJT (Heterojunction) combines crystalline and amorphous silicon layers. Both exceed PERC efficiency with favorabl","u":"engineering-glossary.html#t"},"hjt":{"t":"TOPCon / HJT","d":"Advanced high-efficiency silicon cell technologies. TOPCon (Tunnel Oxide Passivated Contact) adds an ultrathin oxide and doped poly-silicon layer; HJT (Heterojunction) combines crystalline and amorphous silicon layers. Both exceed PERC efficiency with favorabl","u":"engineering-glossary.html#t"},"tracker":{"t":"Tracker","d":"A mounting system that rotates the array to follow the sun, increasing energy capture. Single-axis trackers rotate east-west about a horizontal axis; dual-axis trackers also adjust elevation.","u":"engineering-glossary.html#t"},"transferability":{"t":"Transferability","d":"A provision (introduced by the Inflation Reduction Act) allowing project owners to sell certain federal clean-energy tax credits for cash to unrelated parties, broadening financing options beyond traditional tax equity.","u":"engineering-glossary.html#t"},"transformer":{"t":"Transformer","d":"A device that changes AC voltage levels (e.g. stepping inverter output up to medium-voltage distribution), and may provide galvanic isolation between circuits.","u":"engineering-glossary.html#t"},"ul 1741":{"t":"UL 1741","d":"The safety standard for inverters, converters, and interconnection equipment. The UL 1741-SA/SB supplements add grid-support (&quot;smart inverter&quot;) functions aligned with IEEE 1547.","u":"engineering-glossary.html#u"},"ul 9540":{"t":"UL 9540 / 9540A","d":"UL 9540 is the product safety standard for energy storage systems and equipment; UL 9540A is the companion test method that characterizes thermal-runaway fire propagation in a BESS. UL 9540A results inform NFPA 855 siting and separation requirements.","u":"engineering-glossary.html#u"},"9540a":{"t":"UL 9540 / 9540A","d":"UL 9540 is the product safety standard for energy storage systems and equipment; UL 9540A is the companion test method that characterizes thermal-runaway fire propagation in a BESS. UL 9540A results inform NFPA 855 siting and separation requirements.","u":"engineering-glossary.html#u"},"v2h":{"t":"V2H (Vehicle-to-Home)","d":"A bidirectional EV-charging capability that lets an electric vehicle&#x27;s battery discharge to power a home (and back up loads during outages), turning the vehicle into a mobile storage asset; a subset of broader vehicle-to-grid (V2G).","u":"engineering-glossary.html#v"},"vehicle-to-home":{"t":"V2H (Vehicle-to-Home)","d":"A bidirectional EV-charging capability that lets an electric vehicle&#x27;s battery discharge to power a home (and back up loads during outages), turning the vehicle into a mobile storage asset; a subset of broader vehicle-to-grid (V2G).","u":"engineering-glossary.html#v"},"vder":{"t":"VDER (Value of Distributed Energy Resources)","d":"New York&#x27;s &quot;Value Stack&quot; successor to net metering, compensating distributed solar based on time- and location-specific value components (energy, capacity, environmental, locational) rather than a flat retail credit.","u":"engineering-glossary.html#v"},"value of distributed energy resources":{"t":"VDER (Value of Distributed Energy Resources)","d":"New York&#x27;s &quot;Value Stack&quot; successor to net metering, compensating distributed solar based on time- and location-specific value components (energy, capacity, environmental, locational) rather than a flat retail credit.","u":"engineering-glossary.html#v"},"voc":{"t":"Voc / Isc / Vmp / Imp / Pmax","d":"Core module datasheet parameters: Voc = open-circuit voltage (no load), Isc = short-circuit current (zero voltage), Vmp/Imp = voltage/current at the maximum power point, Pmax = maximum power (Vmp × Imp), all at STC.","u":"engineering-glossary.html#v"},"isc":{"t":"Voc / Isc / Vmp / Imp / Pmax","d":"Core module datasheet parameters: Voc = open-circuit voltage (no load), Isc = short-circuit current (zero voltage), Vmp/Imp = voltage/current at the maximum power point, Pmax = maximum power (Vmp × Imp), all at STC.","u":"engineering-glossary.html#v"},"vmp":{"t":"Voc / Isc / Vmp / Imp / Pmax","d":"Core module datasheet parameters: Voc = open-circuit voltage (no load), Isc = short-circuit current (zero voltage), Vmp/Imp = voltage/current at the maximum power point, Pmax = maximum power (Vmp × Imp), all at STC.","u":"engineering-glossary.html#v"},"imp":{"t":"Voc / Isc / Vmp / Imp / Pmax","d":"Core module datasheet parameters: Voc = open-circuit voltage (no load), Isc = short-circuit current (zero voltage), Vmp/Imp = voltage/current at the maximum power point, Pmax = maximum power (Vmp × Imp), all at STC.","u":"engineering-glossary.html#v"},"pmax":{"t":"Voc / Isc / Vmp / Imp / Pmax","d":"Core module datasheet parameters: Voc = open-circuit voltage (no load), Isc = short-circuit current (zero voltage), Vmp/Imp = voltage/current at the maximum power point, Pmax = maximum power (Vmp × Imp), all at STC.","u":"engineering-glossary.html#v"},"vppa":{"t":"VPPA (Virtual Power Purchase Agreement)","d":"A financial (contract-for-differences) PPA in which a corporate buyer settles against a project&#x27;s market revenue at a fixed strike price and takes the RECs, without taking physical delivery of the power; widely used for corporate renewable procurement.","u":"engineering-glossary.html#v"},"virtual power purchase agreement":{"t":"VPPA (Virtual Power Purchase Agreement)","d":"A financial (contract-for-differences) PPA in which a corporate buyer settles against a project&#x27;s market revenue at a fixed strike price and takes the RECs, without taking physical delivery of the power; widely used for corporate renewable procurement.","u":"engineering-glossary.html#v"},"watt-peak":{"t":"Watt-peak (Wp)","d":"A module&#x27;s rated DC power output at STC; the standard nameplate unit (e.g. a 410 Wp module). System DC size is expressed in kWp (kilowatt-peak).","u":"engineering-glossary.html#w"}};